selector_to_html = {"a[href=\"#py-echo-lidar-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.14 </span>LiDAR data subscription<a class=\"headerlink\" href=\"#py-echo-lidar-data\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_lidar_data</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/lidar_chest_front/</span></code> topic to receive the robot\u2019s LiDAR data, supporting both point cloud and IMU data types.</p><p><strong>Features:</strong></p>", "a[href=\"#py-joint-control\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Robot joint control example<a class=\"headerlink\" href=\"#py-joint-control\" title=\"Link to this heading\">\uf0c1</a></h3><p>This example shows how to use ROS2 and the Ruckig library to control robot joints. The example implements the following features:</p>", "a[href=\"#py-hand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.4 </span>Gripper control<a class=\"headerlink\" href=\"#py-hand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">hand_control</span></code>. Publish messages to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code> topic to control the gripper.</strong></p>", "a[href=\"#py-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.19 </span>Emoji (expression) control<a class=\"headerlink\" href=\"#py-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which enables the robot to display a specified expression. Users can select expressions from the available list. For the full expression list, refer to the <a class=\"reference internal\" href=\"../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">expression list</span></a></p>", "a[href=\"#py-echo-cameras\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.12 </span>Camera stream examples<a class=\"headerlink\" href=\"#py-echo-cameras\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example collection provides multiple camera subscription and processing demos, supporting depth, stereo, and mono camera streams.</strong><br/>\nThese camera subscription examples are not application-level; they only print basic camera data. If you are familiar with ROS2, you can achieve similar results with <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">echo</span></code> + <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">hz</span></code>. You can consult the SDK topic list to jump directly into module development or use these camera examples as scaffolding for your own logic. <strong>The published sensor data are raw (no preprocessing like undistortion). For detailed sensor information (e.g., resolution, focal length), check the corresponding camera_info topic.</strong></p>", "a[href=\"#py-example-expand\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Custom usage<a class=\"headerlink\" href=\"#py-example-expand\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#py-echo-head-touch-sensor\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.13 </span>Head touch sensor data subscription<a class=\"headerlink\" href=\"#py-echo-head-touch-sensor\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_head_touch_sensor</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/touch_head</span></code> topic to receive the robot\u2019s touch sensor data on the head.</p><p><strong>Features:</strong></p>", "a[href=\"#py-motocontrol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.9 </span>Joint motor control<a class=\"headerlink\" href=\"#py-motocontrol\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example demonstrates how to use ROS2 and the Ruckig library to control robot joint motion.</strong></p>", "a[href=\"Cpp.html#cpp-echo-camera-head-rear\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rear Head Monocular Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-head-rear\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_head_rear</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgb_head_rear/</span></code> topic to receive data from the robot\u2019s rear head monocular camera, supporting RGB images (with/without mask), compressed images, and camera intrinsic parameters.</p><p><strong>Features:</strong></p>", "a[href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"]": "<table class=\"docutils align-default\" id=\"tbl-preset-motion\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Action Name</p></th>\n<th class=\"head\"><p><code class=\"docutils literal notranslate\"><span class=\"pre\">motion</span></code></p></th>\n<th class=\"head\"><p><code class=\"docutils literal notranslate\"><span class=\"pre\">area</span></code></p></th>\n<th class=\"head\"><p>Notes</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Right-hand wave</p></td>\n<td><p>1002</p></td>\n<td><p>2</p></td>\n<td><p>switch to Stable Stand first</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand wave</p></td>\n<td><p>1002</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand handshake</p></td>\n<td><p>1003</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand handshake</p></td>\n<td><p>1003</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand raise</p></td>\n<td><p>1001</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand raise</p></td>\n<td><p>1001</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand blow a kiss</p></td>\n<td><p>1004</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand blow a kiss</p></td>\n<td><p>1004</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Clap</p></td>\n<td><p>3017</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Right-hand salute</p></td>\n<td><p>1013</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Left-hand salute</p></td>\n<td><p>1013</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Heart gesture (both hands)</p></td>\n<td><p>1007</p></td>\n<td><p>3</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand heart gesture</p></td>\n<td><p>1007</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand heart gesture</p></td>\n<td><p>1007</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Hug</p></td>\n<td><p>3008</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Cheer</p></td>\n<td><p>3011</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Raise both hands</p></td>\n<td><p>1010</p></td>\n<td><p>3</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Raise right hand</p></td>\n<td><p>1010</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Raise left hand</p></td>\n<td><p>1010</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Wave goodbye</p></td>\n<td><p>3031</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Dynamic light wave</p></td>\n<td><p>3007</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Right-hand high-five</p></td>\n<td><p>1008</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Left-hand high-five</p></td>\n<td><p>1008</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Cross arms</p></td>\n<td><p>3009</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand wave at chest</p></td>\n<td><p>1011</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand wave at chest</p></td>\n<td><p>1011</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Bow</p></td>\n<td><p>3001</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Scratch head</p></td>\n<td><p>3024</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Grab buttocks</p></td>\n<td><p>3025</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#py-locomotion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.8 </span>Control robot locomotion<a class=\"headerlink\" href=\"#py-locomotion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">mc_locomotion_velocity</span></code>. The example below controls robot walking by publishing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/mc/locomotion/velocity</span></code> topic. For versions after v0.7, you must register an input source before enabling velocity control (this example already registers an input source); see the code for registration steps.</strong></p><p>Start the node after switching to Stable Standing Mode:</p>", "a[href=\"#py-take-photo\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.11 </span>Take photo<a class=\"headerlink\" href=\"#py-take-photo\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">take_photo</span></code>. Before running the node, set the camera topic to capture. When started, the node creates an <code class=\"docutils literal notranslate\"><span class=\"pre\">/images/</span></code> directory and saves the current frame into that directory.</strong></p>", "a[href=\"#py-mic-receiver\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.18 </span>Microphone data reception<a class=\"headerlink\" href=\"#py-mic-receiver\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mic_receiver</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/agent/process_audio_output</span></code> topic to receive noise-reduced audio data from the robot, supporting both internal and external microphone audio streams, and automatically saving complete speech segments as PCM files based on VAD (Voice Activity Detection) status.</p><p><strong>Features:</strong></p>", "a[href=\"#python\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1 </span>Python interface usage example<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This chapter will guide you through implementing several features shown in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"]": "<table class=\"docutils align-default\" id=\"tbl-mc-action\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Mode</p></th>\n<th class=\"head\"><p>Value</p></th>\n<th class=\"head\"><p>Description</p></th>\n<th class=\"head\"><p>Use cases</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Zero-Torque Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">PASSIVE_DEFAULT</span></code></p></td>\n<td><p>Robot joints zero torque, free state</p></td>\n<td><p>System startup, maintenance, soft e-stop</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Damping Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">DAMPING_DEFAULT</span></code></p></td>\n<td><p>The joint exhibits a damping effect</p></td>\n<td><p>Safe movement</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Position-controlled Stand</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">JOINT_DEFAULT</span></code></p></td>\n<td><p>Position-controlled stand</p></td>\n<td><p>Precise joint position control</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Stable Stand</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code></p></td>\n<td><p>Active force to ensure standing</p></td>\n<td><p>Dynamic balance control, walking/action ready state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Locomotion Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code></p></td>\n<td><p>Normal walking/running</p></td>\n<td><p>Daily movement</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#py-echo-camera-head-rear\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Head rear monocular camera data subscription<a class=\"headerlink\" href=\"#py-echo-camera-head-rear\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">echo_camera_head_rear</span></code> to subscribe to <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgb_head_rear/</span></code> and receive the robot\u2019s head rear monocular camera data, supporting RGB images, compressed images, and camera intrinsics.</strong></p><p><strong>Features:</strong></p>", "a[href=\"../Interface/interactor/screen.html#tbl-emotion-id\"]": "<table class=\"docutils align-default\" id=\"tbl-emotion-id\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Emoji ID</p></th>\n<th class=\"head\"><p>Emoji name</p></th>\n<th class=\"head\"><p>Description</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>1</p></td>\n<td><p>Blink</p></td>\n<td><p>Basic blink action</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>10</p></td>\n<td><p>Calm - eye variation 1</p></td>\n<td><p>Eye variation for calm state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>11</p></td>\n<td><p>Calm - eye variation 2</p></td>\n<td><p>Eye variation for calm state</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>20</p></td>\n<td><p>Calm - game</p></td>\n<td><p>Game-state emoji</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>30-33</p></td>\n<td><p>Calm - cute</p></td>\n<td><p>Cute expression series</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>40</p></td>\n<td><p>Close eyes</p></td>\n<td><p>Close-eye action</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>50</p></td>\n<td><p>Open eyes</p></td>\n<td><p>Open-eye action</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>60</p></td>\n<td><p>Bored</p></td>\n<td><p>Bored expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>70</p></td>\n<td><p>Abnormal</p></td>\n<td><p>Abnormal state</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>80</p></td>\n<td><p>Sleeping</p></td>\n<td><p>Sleeping state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>90</p></td>\n<td><p>Happy</p></td>\n<td><p>Happy expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>100-101</p></td>\n<td><p>Extra happy / ecstatic</p></td>\n<td><p>Extremely happy expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>110</p></td>\n<td><p>Sad</p></td>\n<td><p>Sad expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>120</p></td>\n<td><p>Sympathy</p></td>\n<td><p>Sympathetic expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>130</p></td>\n<td><p>Confused</p></td>\n<td><p>Confused expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>140</p></td>\n<td><p>Shocked</p></td>\n<td><p>Shocked expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>150</p></td>\n<td><p>Acting cute</p></td>\n<td><p>Cute/affectionate expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>160</p></td>\n<td><p>Serious</p></td>\n<td><p>Serious expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>170</p></td>\n<td><p>Thinking</p></td>\n<td><p>Thinking expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>180</p></td>\n<td><p>Angry</p></td>\n<td><p>Angry expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>190</p></td>\n<td><p>Extra angry</p></td>\n<td><p>Extremely angry expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>200</p></td>\n<td><p>Adoration</p></td>\n<td><p>Adoring expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>210</p></td>\n<td><p>Extra adoring</p></td>\n<td><p>Extremely adoring expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>220</p></td>\n<td><p>Charging</p></td>\n<td><p>Charging state</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#py-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.10 </span>Keyboard control<a class=\"headerlink\" href=\"#py-keyboard\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example implements robot forward/backward and turning control using keyboard input from a PC.</strong></p><p><strong>Use <kbd class=\"kbd docutils literal notranslate\">W</kbd> <kbd class=\"kbd docutils literal notranslate\">A</kbd> <kbd class=\"kbd docutils literal notranslate\">S</kbd> <kbd class=\"kbd docutils literal notranslate\">D</kbd> to control robot direction; increase/decrease speed by \u00b10.2 m/s. Use <kbd class=\"kbd docutils literal notranslate\">Q</kbd>/<kbd class=\"kbd docutils literal notranslate\">E</kbd> to increase/decrease angular speed by \u00b10.1 rad/s. Press <kbd class=\"kbd docutils literal notranslate\">ESC</kbd> to exit and release terminal resources. <font style=\"color: red\">Press <kbd class=\"kbd docutils literal notranslate\">Space</kbd> to immediately zero speed (emergency stop)</font>.</strong></p>", "a[href=\"#py-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.15 </span>Play video<a class=\"headerlink\" href=\"#py-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video</strong>. Before running the node, you must upload the video to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory on it to store videos, e.g. /var/tmp/videos/), and then change the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"#py-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.2 </span>Set robot mode<a class=\"headerlink\" href=\"#py-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"#py-omnihand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.5 </span>Dexterous Hand Control<a class=\"headerlink\" href=\"#py-omnihand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">omnihand_control</span></code>. Publish messages to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code> topic to control the omnihand.</strong></p>", "a[href=\"#py-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.6 </span>Register custom input source<a class=\"headerlink\" href=\"#py-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, you must register an input source before controlling the MC. This example registers a custom input source via the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service so MC becomes aware of it; only registered input sources can perform robot velocity control.</strong></p>", "a[href=\"Cpp.html#cpp-echo-camera-rgbd\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Depth Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-rgbd\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_rgbd</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgbd_head_front/</span></code> topic to receive depth camera data, supporting multiple data types including depth point clouds, depth images, RGB images, compressed RGB images, and camera intrinsic parameters.</p><p><strong>Features:</strong></p>", "a[href=\"#py-echo-camera-rgbd\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Depth camera data subscription<a class=\"headerlink\" href=\"#py-echo-camera-rgbd\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">echo_camera_rgbd</span></code> to subscribe to <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgbd_head_front/</span></code> and receive the robot\u2019s depth camera data. It supports depth pointclouds, depth images, RGB images, compressed RGB images, and camera intrinsics.</strong></p><p><strong>Features:</strong></p>", "a[href=\"#py-echo-camera-stereo\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Stereo camera data subscription<a class=\"headerlink\" href=\"#py-echo-camera-stereo\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">echo_camera_stereo</span></code> to subscribe to <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/stereo_head_front_*/</span></code> and receive stereo camera data from the robot, supporting left/right RGB images, compressed images, and camera intrinsics.</strong></p><p><strong>Features:</strong></p>", "a[href=\"#py-preset-motion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.3 </span>Set robot action<a class=\"headerlink\" href=\"#py-preset-motion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">preset_motion_client</span></code></strong>; after switching to Stable Stand Mode and starting the node, enter the corresponding field values to perform preset actions with the left (or right) hand such as handshake, raise hand, wave, or air kiss.</p><p>Available parameters are listed in the <a class=\"reference internal\" href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"><span class=\"std std-ref\">preset motions table</span></a></p>", "a[href=\"#py-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.7 </span>Get current input source<a class=\"headerlink\" href=\"#py-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetCurrentInputSource</span></code> service</strong> to retrieve information about the currently registered input source, including name, priority, and timeout.</p>", "a[href=\"Cpp.html#cpp-echo-camera-stereo\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Stereo Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-stereo\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_stereo</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/stereo_head_front_*/</span></code> topics to receive stereo camera data, supporting RGB images, compressed images, and camera intrinsic parameters from both the left and right cameras.</p><p><strong>Features:</strong></p>", "a[href=\"#py-play-media\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.16 </span>Media file playback<a class=\"headerlink\" href=\"#py-play-media\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_media</strong>, which enables playback of specified media files (such as audio files) through the node, supporting audio formats including WAV and MP3.</p><p><strong>Features:</strong></p>", "a[href=\"#py-play-tts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.17 </span>TTS (Text-to-Speech)<a class=\"headerlink\" href=\"#py-play-tts\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_tts</strong>, which enables the robot to speak the provided text through the node. Users can input different text according to various scenarios.</p><p><strong>Features:</strong></p>", "a[href=\"#py-example-explain\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Example feature description<a class=\"headerlink\" href=\"#py-example-explain\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#py-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.1 </span>Get robot mode<a class=\"headerlink\" href=\"#py-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>", "a[href=\"#py-play-lights\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.20 </span>LED light strip control<a class=\"headerlink\" href=\"#py-play-lights\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Function description</strong>: Demonstrates how to control the robot\u2019s LED light strip, supporting multiple display modes and custom colors.</p><p><strong>Core code:</strong></p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
